joi_block.script:
hold_ticks := 0
fired := false
if ((#Light #Hallway).light_currentBrightness > 0) {
if (fired == false) {
hold_ticks = hold_ticks + 1
        if (hold_ticks >= 301) {
all(#Light #LivingRoom).light_moveToBrightness(0, 0)
            fired = true
}
}
}
else {
hold_ticks = 0
    fired = false
}

